--------------------------------------------------------
--  DDL for Trigger TRG2
--------------------------------------------------------

  CREATE OR REPLACE NONEDITIONABLE TRIGGER "HR"."TRG2" 
BEFORE UPDATE OF SALARY ON EMPLOYEES
FOR EACH ROW

DECLARE
    SAL_DIF NUMBER;
 BEGIN
   IF :NEW.SALARY < :OLD.SALARY THEN
      RAISE_APPLICATION_ERROR('-20205','EL SALARIO NO PUEDE SER MAS BAJO QUE EL ACTUAL');
     end if; 
    DBMS_OUTPUT.PUT_LINE(' NEW ' || :NEW.EMPLOYEE_ID || ' OLD ' || :OLD.EMPLOYEE_ID);
    SAL_DIF := :NEW.SALARY - :OLD.SALARY;
    DBMS_OUTPUT.PUT_LINE(' NEW ' || :NEW.SALARY);
    DBMS_OUTPUT.PUT_LINE(' OLD ' || :OLD.SALARY);
    DBMS_OUTPUT.PUT_LINE(' SAL_DIF ' || SAL_DIF);
 END;   

/
ALTER TRIGGER "HR"."TRG2" DISABLE;
--------------------------------------------------------
--  DDL for Trigger UPDATE_JOB_HISTORY
--------------------------------------------------------

  CREATE OR REPLACE NONEDITIONABLE TRIGGER "HR"."UPDATE_JOB_HISTORY" 
  AFTER UPDATE OF job_id, department_id ON employees
  FOR EACH ROW
BEGIN
  add_job_history(:old.employee_id, :old.hire_date, sysdate, 
                  :old.job_id, :old.department_id);
END;

/
ALTER TRIGGER "HR"."UPDATE_JOB_HISTORY" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG1
--------------------------------------------------------

  CREATE OR REPLACE NONEDITIONABLE TRIGGER "HR"."TRG1" 
  AFTER UPDATE OF SALARY
  ON EMPLOYEES
  FOR EACH ROW
  BEGIN
        IF :NEW.SALARY > 15000 THEN
          UPDATE EMPLOYEES SET COMMISSION_PCT = TRUNC(:NEW.SALARY*.00000365,2)
          WHERE EMPLOYEE_ID = :OLD.EMPLOYEE_ID;
        END IF;

  END;
/
ALTER TRIGGER "HR"."TRG1" DISABLE;
